import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Google Drive Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/google-drive.md","filePath":"ur/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"ur/upload/google-drive.md"};function c(p,e,h,g,u,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="google-drive-channel-شامل-کریں" tabindex="-1">Google Drive Channel شامل کریں <a class="header-anchor" href="#google-drive-channel-شامل-کریں" aria-label="Permalink to &quot;Google Drive Channel شامل کریں&quot;">​</a></h1><h2 id="شروع-کرنے-سے-پہلے-کیا-چاہیے" tabindex="-1">شروع کرنے سے پہلے کیا چاہیے <a class="header-anchor" href="#شروع-کرنے-سے-پہلے-کیا-چاہیے" aria-label="Permalink to &quot;شروع کرنے سے پہلے کیا چاہیے&quot;">​</a></h2><p>شروع کرنے سے پہلے یہ items تیار کریں:</p><table tabindex="0"><thead><tr><th>ضرورت</th><th>وجہ</th></tr></thead><tbody><tr><td>Google account</td><td>Google Cloud تک access اور Google Drive authorize کرنے کے لیے</td></tr><tr><td>Google Cloud project</td><td>Drive API enable کرنے اور OAuth credentials بنانے کے لیے</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed کے لیے <code>Client ID</code>، <code>Client Secret</code>، اور <code>Refresh Token</code> حاصل کرنے کے لیے</td></tr><tr><td>آپ کا ImgBed domain</td><td>OAuth redirect URI کے لیے۔ یہ اسی domain سے match ہونا چاہیے جو آپ واقعی استعمال کرتے ہیں۔</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-google-drive-api-enable-کریں" tabindex="-1">Step 1: Google Drive API Enable کریں <a class="header-anchor" href="#step-1-google-drive-api-enable-کریں" aria-label="Permalink to &quot;Step 1: Google Drive API Enable کریں&quot;">​</a></h3><ol><li>Google Cloud Console کھولیں۔</li><li>نیا project بنائیں یا existing project منتخب کریں۔</li><li><code>APIs &amp; Services</code> میں جائیں۔</li><li><code>Enable APIs and Services</code> پر کلک کریں۔</li><li><code>Google Drive API</code> تلاش کریں۔</li><li>اسے کھولیں اور enable پر کلک کریں۔</li></ol><h3 id="step-2-oauth-consent-screen-configure-کریں" tabindex="-1">Step 2: OAuth Consent Screen Configure کریں <a class="header-anchor" href="#step-2-oauth-consent-screen-configure-کریں" aria-label="Permalink to &quot;Step 2: OAuth Consent Screen Configure کریں&quot;">​</a></h3><ol><li>Google Cloud میں <code>Google Auth Platform</code> کھولیں۔</li><li>basic <code>Branding</code> information مکمل کریں، جیسے app name، support email، اور developer contact email۔</li><li><code>Audience</code> کھولیں۔</li><li>زیادہ تر self-hosted personal deployments کے لیے <code>External</code> منتخب کریں۔</li><li>اگر <code>External</code> منتخب کرتے ہیں تو جس Google account کو authorize کرنا ہے اسے <code>Test users</code> میں شامل کریں۔</li><li><code>Data Access</code> کھولیں۔</li><li>درکار Google Drive permissions شامل کریں۔</li></ol><h3 id="step-3-oauth-2-0-client-بنائیں" tabindex="-1">Step 3: OAuth 2.0 Client بنائیں <a class="header-anchor" href="#step-3-oauth-2-0-client-بنائیں" aria-label="Permalink to &quot;Step 3: OAuth 2.0 Client بنائیں&quot;">​</a></h3><ol><li><code>Google Auth Platform</code> میں <code>Clients</code> کھولیں۔</li><li>نیا client بنائیں۔</li><li>application type کو <code>Web application</code> رکھیں۔</li><li>client کو قابل شناخت نام دیں۔</li><li>authorized JavaScript origins میں اپنا ImgBed URL درج کریں، مثلاً:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>authorized redirect URIs میں درج کریں:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>client بننے کے بعد یہ values copy کریں:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-imgbed-میں-google-drive-channel-بھریں" tabindex="-1">Step 4: ImgBed میں Google Drive Channel بھریں <a class="header-anchor" href="#step-4-imgbed-میں-google-drive-channel-بھریں" aria-label="Permalink to &quot;Step 4: ImgBed میں Google Drive Channel بھریں&quot;">​</a></h2><p>Upload Settings میں <code>Google Drive</code> منتخب کریں اور یہ fields بھریں:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>قابل شناخت نام، مثلاً <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Google Cloud سے لیا ہوا Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud سے لیا ہوا Client Secret</td></tr><tr><td>Refresh Token</td><td>ابھی خالی چھوڑ دیں۔ اگلے step میں حاصل کریں۔</td></tr><tr><td>Root directory</td><td>Optional۔ default <code>imgbed</code> ہے۔</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-refresh-token-حاصل-کریں" tabindex="-1">Step 5: Refresh Token حاصل کریں <a class="header-anchor" href="#step-5-refresh-token-حاصل-کریں" aria-label="Permalink to &quot;Step 5: Refresh Token حاصل کریں&quot;">​</a></h2><ol><li><code>Get Token</code> پر کلک کریں۔</li><li>وہ Google account منتخب کریں جسے connect کرنا ہے۔</li><li>authorization prompts مکمل کریں۔</li><li>callback page ایک <code>Refresh Token</code> دکھائے گا۔</li><li>اسے copy کریں۔</li><li>ImgBed پر واپس آ کر <code>Refresh Token</code> field میں paste کریں۔</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>اگر بعد میں Google account بدلیں، OAuth client بدلیں، یا پرانی authorization expire ہو جائے، تو channel delete کرنے کی ضرورت نہیں۔ edit page کھولیں اور <code>Reauthorize</code> پر کلک کریں۔</p><h2 id="step-6-channel-save-کریں" tabindex="-1">Step 6: Channel Save کریں <a class="header-anchor" href="#step-6-channel-save-کریں" aria-label="Permalink to &quot;Step 6: Channel Save کریں&quot;">​</a></h2><p>تمام fields بھرنے کے بعد channel save کریں۔</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud کھولیں</span></span>
<span class="line"><span>-&gt; project بنائیں یا منتخب کریں</span></span>
<span class="line"><span>-&gt; Google Drive API enable کریں</span></span>
<span class="line"><span>-&gt; Google Auth Platform configure کریں</span></span>
<span class="line"><span>-&gt; Audience External ہو تو اپنا Google account Test users میں شامل کریں</span></span>
<span class="line"><span>-&gt; Web application OAuth client بنائیں</span></span>
<span class="line"><span>-&gt; redirect URI کے طور پر https://your-domain.com/api/oauth/google/callback استعمال کریں</span></span>
<span class="line"><span>-&gt; Client ID اور Client Secret ImgBed میں بھریں</span></span>
<span class="line"><span>-&gt; Get Token پر کلک کریں</span></span>
<span class="line"><span>-&gt; Google سے sign in اور authorize کریں</span></span>
<span class="line"><span>-&gt; callback page سے Refresh Token copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں paste کر کے save کریں</span></span>
<span class="line"><span>-&gt; test image upload کریں</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const k=i(d,[["render",c]]);export{f as __pageData,k as default};
